import React, { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./AppraisalForm.css";

export default function AppraisalForm() {

  const navigate = useNavigate();
  const { id } = useParams();

  /* =============================
     ROLE BASE ROUTING
  ============================== */
  const loggedUser =
    JSON.parse(localStorage.getItem("loggedInUser")) || {};

  const base =
    loggedUser?.role?.toUpperCase() === "ADMIN"
      ? "/admin-dashboard"
      : "/employee-dashboard";

  /* =============================
     STATE
  ============================== */
  const [employees, setEmployees] = useState([]);

  const [formData, setFormData] = useState({
    employeeName: "",
    department: "",
    period: "Jan 2024 - Dec 2024",
    rating: "",
    status: "Pending",
  });

  const [errors, setErrors] = useState({});

  /* =============================
     SAFE NAME RESOLVER ⭐⭐⭐
     Prevents blank screen crash
  ============================== */
  const getEmployeeName = (emp) => {
    const first = emp?.firstName?.trim() || "";
    const last = emp?.lastName?.trim() || "";

    if (first || last) return `${first} ${last}`.trim();
    if (emp?.name) return emp.name;

    return "Unnamed";
  };

  /* =============================
     LOAD EMPLOYEES
  ============================== */
  useEffect(() => {
    const emp = JSON.parse(localStorage.getItem("employees")) || [];
    setEmployees(emp);
  }, []);

  /* =============================
     LOAD EDIT DATA
  ============================== */
  useEffect(() => {
    if (!id) return;

    const stored = JSON.parse(localStorage.getItem("appraisals")) || [];
    const record = stored.find(a => String(a.id) === String(id));

    if (record) setFormData(record);
  }, [id]);

  /* =============================
     HANDLE INPUT CHANGE
  ============================== */
  const handleChange = (e) => {
    const { name, value } = e.target;

    // Auto department from selected employee
    if (name === "employeeName") {
      const emp = employees.find(
        (e) => getEmployeeName(e) === value
      );

      setFormData({
        ...formData,
        employeeName: value,
        department: emp ? emp.department : "",
      });
      return;
    }

    setFormData({
      ...formData,
      [name]: value,
    });
  };

  /* =============================
     VALIDATION
  ============================== */
  const validate = () => {
    let temp = {};

    if (!formData.employeeName)
      temp.employeeName = "Employee required";

    if (!formData.department)
      temp.department = "Department required";

    if (!formData.rating)
      temp.rating = "Rating required";
    else if (formData.rating < 0 || formData.rating > 5)
      temp.rating = "0–5 only";

    setErrors(temp);
    return Object.keys(temp).length === 0;
  };

  /* =============================
     SUBMIT
  ============================== */
  const handleSubmit = (e) => {
    e.preventDefault();
    if (!validate()) return;

    const stored = JSON.parse(localStorage.getItem("appraisals")) || [];

    // EDIT MODE
    if (id) {
      const updated = stored.map(a =>
        String(a.id) === String(id)
          ? { ...formData, id: a.id }
          : a
      );

      localStorage.setItem("appraisals", JSON.stringify(updated));
      alert("Appraisal Updated Successfully");
    }

    // ADD MODE
    else {
      const newRecord = {
        id: Date.now(),
        ...formData,
      };

      stored.push(newRecord);
      localStorage.setItem("appraisals", JSON.stringify(stored));
      alert("Appraisal Added Successfully");
    }

    navigate(`${base}/appraisal`);
  };

  /* =============================
     UI
  ============================== */
  return (
    <div className="appraisal-form-scope">
      <div className="appraisal-form-card">

        <h2>
          {id ? "Edit Employee Appraisal" : "Add Employee Appraisal"}
        </h2>

        <form className="appraisal-form" onSubmit={handleSubmit}>

          {/* Employee */}
          <label>Employee Name</label>
          <select
            name="employeeName"
            value={formData.employeeName}
            onChange={handleChange}
          >
            <option value="">Select Employee</option>

            {employees.map(emp => {
              const displayName = getEmployeeName(emp);
              return (
                <option key={emp.id} value={displayName}>
                  {displayName}
                </option>
              );
            })}
          </select>
          {errors.employeeName &&
            <p className="error-text">{errors.employeeName}</p>}

          {/* Department */}
          <label>Department</label>
          <input
            name="department"
            value={formData.department}
            disabled
          />

          {/* Period */}
          <label>Review Period</label>
          <input
            name="period"
            value={formData.period}
            onChange={handleChange}
          />

          {/* Rating */}
          <label>Rating</label>
          <input
            type="number"
            step="0.1"
            name="rating"
            value={formData.rating}
            onChange={handleChange}
          />
          {errors.rating &&
            <p className="error-text">{errors.rating}</p>}

          {/* Status */}
          <label>Status</label>
          <select
            name="status"
            value={formData.status}
            onChange={handleChange}
          >
            <option>Pending</option>
            <option>Approved</option>
            <option>Rejected</option>
          </select>

          {/* Buttons */}
          <div className="appraisal-btn-row">

            <button
              type="submit"
              className="appraisal-save-btn"
            >
              Save
            </button>

            <button
              type="button"
              className="appraisal-cancel-btn"
              onClick={() => navigate(`${base}/appraisal`)}
            >
              Cancel
            </button>

          </div>

        </form>
      </div>
    </div>
  );
}
